```python
class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.current_player = 'r'

    def print_board(self):
        self.board.print_board()

    def get_valid_moves(self, player):
        valid_moves = []
        for row in range(self.board.size):
            for col in range(self.board.size):
                if self.board.board[row][col] == player:
                    moves = self.get_piece_moves((row, col))
                    for move in moves:
                        valid_moves.append((row, col, *move))
        return valid_moves

    def get_piece_moves(self, position):
        row, col = position
        moves = []
        directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
        for direction in directions:
            new_row, new_col = row + direction[0], col + direction[1]
            if self.board.is_valid_move(position, (new_row, new_col)):
                moves.append((new_row, new_col))
                # Check for jumps
                jump_row, jump_col = new_row + direction[0], new_col + direction[1]
                while 0 <= jump_row < self.board.size and 0 <= jump_col < self.board.size:
                    if self.board.is_valid_move((new_row, new_col), (jump_row, jump_col)):
                        moves.append((jump_row, jump_col))
                        new_row, new_col = jump_row, jump_col
                    else:
                        break
        return moves

    def make_move(self, from_pos, to_pos):
        self.board.make_move(from_pos, to_pos)

    def switch_player(self):
        if self.current_player == 'r':
            self.current_player = 'b'
        else:
            self.current_player = 'r'

    def play_game(self):
        while True:
            print(f"Current player: {self.current_player}")
            self.print_board()
            valid_moves = self.get_valid_moves(self.current_player)
            if not valid_moves:
                print("No valid moves. Switching players...")
                self.switch_player()
                continue

            from_pos, to_pos = input("Enter move (from-to): ").split('-')
            from_pos = tuple(map(int, from_pos.split()))
            to_pos = tuple(map(int, to_pos.split()))

            try:
                self.make_move(from_pos, to_pos)
            except ValueError as e:
                print(e)
                continue

            winner = self.board.check_winner()
            if winner:
                print(f"Game Over! {winner}")
                break
