```python
import re

class Checkers:
    def __init__(self):
        self.board = [
            ['B' if (i + j) % 2 else ' ' for i in range(8)] for j in range(8)
        ]
        for i in range(3):
            for j in range(4):
                if (i + j) % 2:
                    self.board[i][j] = 'b'
                elif (i + j) % 2 == 0 and (i < 5 or j > 2):
                    self.board[7 - i][j] = 'R' if (i + j) % 2 else 'r'

    def print_board(self):
        for row in self.board:
            print(" ".join(row))
        print()

    def is_valid_move(self, start, end):
        x1, y1 = map(int, start.split(','))
        x2, y2 = map(int, end.split(','))
        piece = self.board[x1][y1]

        if piece == ' ' or (piece.islower() and x2 < x1) or (piece.isupper() and x2 > x1):
            return False

        dx, dy = abs(x2 - x1), abs(y2 - y1)
        if dx != 1 or dy not in [1, 2]:
            return False

        if self.board[x2][y2] != ' ':
            return False

        if dy == 2:
            intermediate_x, intermediate_y = (x1 + x2) // 2, (y1 + y2) // 2
            if self.board[intermediate_x][intermediate_y].islower() == piece.islower():
                return False

        return True

    def make_move(self, start, end):
        x1, y1 = map(int, start.split(','))
        x2, y2 = map(int, end.split(','))
        self.board[x2][y2] = self.board[x1][y1]
        self.board[x1][y1] = ' '

        dx, dy = abs(x2 - x1), abs(y2 - y1)
        if dy == 2:
            intermediate_x, intermediate_y = (x1 + x2) // 2, (y1 + y2) // 2
            self.board[intermediate_x][intermediate_y] = ' '

        if dx == 2 and abs(y2 - y1) == 1 and piece.islower() and x2 == 7:
            self.board[x2][y2] = 'R'
        elif dx == 2 and abs(y2 - y1) == 1 and piece.isupper() and x2 == 0:
            self.board[x2][y2] = 'r'

    def has_legal_moves(self, player):
        for i in range(8):
            for j in range(8):
                if (player == 'B' and self.board[i][j] in ['b', 'R']) or (player == 'R' and self.board[i][j] in ['r', 'B']):
                    for x, y in [(i+1, j-1), (i+1, j+1)]:
                        if 0 <= x < 8 and 0 <= y < 8 and self.is_valid_move(f'{i},{j}', f'{x},{y}'):
                            return True
        return False

    def get_moves(self, start):
        moves = []
        x1, y1 = map(int, start.split(','))
        piece = self.board[x1][y1]

        for dx in range(-2, 3):
            for dy in range(-2, 3):
                if abs(dx) != abs(dy) and 0 <= x1 + dx < 8 and 0 <= y1 + dy < 8:
                    if self.is_valid_move(f'{x1},{y1}', f'{x1+dx},{y1+dy}'):
                        moves.append(f'{x1+dx},{y1+dy}')

        return moves

    def play(self):
        current_player = 'B'
        while True:
            self.print_board()
            if not self.has_legal_moves(current_player):
                print(f"Player {current_player} has no legal moves. Game over.")
                break

            move = input(f"Player {current_player}, enter your move (e.g., 2,3 to 4,5): ")
            while not re.match(r'^\d+,\d+\s*->\s*\d+,\d+$', move):
                move = input("Invalid move format. Enter again: ")

            start, end = move.split(' -> ')
            if not self.is_valid_move(start.strip(), end.strip()):
                print("Invalid move. Try again.")
                continue

